features.snippet:
interface intf;
  logic blargh;
endinterface

function automatic logic ident_func(logic a);
  return a;
endfunction

module top(intf intf_a);
  always_comb begin
    if (ident_func(1'b1))
      intf_a.blargh = 1'b0;
  end
endmodule

interface intf;
  logic data;
endinterface

function automatic logic ident_func(logic a);
  return a;
endfunction

module top(intf intf_a, intf intf_b);
  always_comb begin
    if (ident_func(intf_b.data))
      intf_a.data = 1'b0;
  end
endmodule
